var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"후아… 다 처리했다.","JPN":"ふわぁ……最後の一匹まで処理完了っと。","ENG":"Huah...! That's all of them.","TWN":"啊哈……全部搞定。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"예상은 했지만, 격리실은 텅텅 비었네.","JPN":"予想通り、隔離室にはもう誰もいないみたいね。","ENG":"As expected, the quarantine room is empty.","TWN":"不出所料，隔離室空無一人。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"애초에 얌전히 있을 줄 알았다면, 이런 번거로운 계획은 세우지도 않았겠지만…","JPN":"だいたい、大人しくしているってわかってたらこんな複雑な計画を立てる必要はなかっただろう。","ENG":"But if we thought the kid would stay in here, we wouldn't have come up with such a bothersome plan in the first place...","TWN":"不過如果她會乖乖待在這裡，我們就不用制定這麼麻煩的計畫了吧……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"뭐, 나머진 그 사람에게 맡기면 되겠지?","JPN":"まぁ、あとはあの人に任せておけばいっか。","ENG":"Well, I guess I can leave the rest to her, right?","TWN":"好，剩下的就交給她吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"킁, 킁킁.","JPN":"くんくん、くんくん","ENG":"*Sniff* *Sniff*","TWN":"咳、咳咳。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"우웩- 나 피를 얼마나 흘린 거야? 좀 씻고 싶다.","JPN":"げっ！　私どんだけ流血してるの？　お風呂入りたい～。","ENG":"Blech! How much blood did I spill? I could go for a shower about now.","TWN":"哇——我流了多少血？好想去沖個澡耶。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"앗, 샤워기 발견!","JPN":"あっ、シャワー発見！","ENG":"Ooh! There's a shower right there!","TWN":"啊，找到淋浴間了！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"읏퉤퉤…!","JPN":"おええっ、ぺっ、ぺっ！","ENG":"Ptui...!","TWN":"呸呸呸……！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"전부 녹물이잖아. 최악.","JPN":"なにこれ赤水？　もう最悪。","ENG":"The water's all rusted. Ugh.","TWN":"都是些鏽水，太糟糕了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"응…?","JPN":"ん……？","ENG":"Hmm...?","TWN":"嗯……？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"감지센서에 잡히는 움직임이 하나도 없어.","JPN":"感知センサーにはなんの動きも捉えられていないな。","ENG":"The sensor isn't picking up any movement.","TWN":"感應器沒有感應到任何移動跡象。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"셰퍼드가 말한 <color=#ffd34c>집</color>이 이곳엔 없는 건가?","JPN":"シェパードの言っていた<color=#ffd34c>おウチ</color>はここじゃないのか？","ENG":"Maybe the <color=#ffd34c>home</color> Shepherd mentioned isn't here?","TWN":"牧羊犬說的<color=#ffd34c>家</color>不是這裡嗎？"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"가만.","JPN":"待て、これは？","ENG":"Hold on.","TWN":"等下。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"15번 카메라가 뭔가로 가려져 있어.","JPN":"15番カメラが何かに覆われている。","ENG":"Something's covering up camera 15.","TWN":"15號攝影機被什麼東西遮住了。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"카메라로 확인할 수 없다면 직접 가보는 수밖에 없겠네.","JPN":"カメラで確認できないなら、直接確認しに行くしかないな。","ENG":"If I can't see it through the camera, I'll have to go see it in person.","TWN":"無法用攝影機查看的話，那就只能親自去一趟了。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이 소리… 통로 쪽인가?","JPN":"この音は……通路側？","ENG":"That sound... Is it coming from down the aisle?","TWN":"這聲音……是在通道嗎？"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"기억 나. 다이빙 벨이 추락할 때도 어둠 속에서 이런 소리를 들었어.","JPN":"この音、聞き覚えがある。ダイビングベルが墜落したときも、暗闇でこの音が聞こえた。","ENG":"I remember that sound. I heard it in the dark when the Diving Bell went down.","TWN":"我想起來了。潛水鐘墜下來時，我在黑暗中聽到過這個聲音。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"설마 이쪽으로 오는 건가?","JPN":"まさか、こっちに来るのか？","ENG":"Is it coming this way?","TWN":"難道是從那邊傳來的？"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"스펜서!","JPN":"スペンサーさん！","ENG":"Spencer!","TWN":"史賓瑟！"},"stage":{"bg":"DATABASE_02","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"지금 도망쳐야 해요! 골치 아픈 침식체가 오고 있어요!","JPN":"早く逃げましょう！　厄介な侵食体がこちらに向かってきています！","ENG":"We gotta run! That troublesome C.O. is headed this way!","TWN":"快跑！有一個難纏的侵蝕體往這邊來了！"},"stage":{"bg":"DATABASE_02","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"예니카?","JPN":"イェニカ？","ENG":"Yanikka?","TWN":"耶妮卡？"},"stage":{"bg":"DATABASE_02","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"도망치라니. 대체 어디로?","JPN":"逃げるって、どこに？","ENG":"Run? But where to?","TWN":"逃？但是要逃去哪裡？"},"stage":{"bg":"DATABASE_02","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"여기서 최대한 멀리요! 그리고 <color=#ffd34c>녀석</color>을 따돌린 뒤에 그 셰퍼드란 아이를 찾으세요!","JPN":"とにかく、できるだけ遠くにです！　それと<color=#ffd34c>アイツ</color>から逃げ切ったら、そのシェパードって子を見つけ出してください！","ENG":"As far from here as possible! And after you lose <color=#ffd34c>it</color>, go find that Shepherd girl!","TWN":"盡可能遠離這裡！甩掉那<color=#ffd34c>傢伙</color>後，去找那個叫牧羊犬的孩子！"},"stage":{"bg":"DATABASE_02","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>녀석</color>을 막으려면 그 애가 필요해요!","JPN":"<color=#ffd34c>アイツ</color>を止められるのは、その子だけです！","ENG":"We need her to stop <color=#ffd34c>it</color>!","TWN":"我們需要那孩子幫忙攔住這<color=#ffd34c>傢伙</color>！"},"stage":{"bg":"DATABASE_02","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};